30: /**
31:  * A scheduler based on java.util.concurrent.ScheduledThreadPoolExecutor
32:  * <br>
33:  * It has a pool of kafka-scheduler- threads that do the actual work.
34:  */
35: public class KafkaScheduler implements Scheduler {
36: 
37:     private static class NoOpScheduledFutureTask implements ScheduledFuture<Void> {
38: 
39:         @Override
40:         public boolean cancel(boolean mayInterruptIfRunning) {
41:             return true;
42:         }
43: 
44:         @Override
45:         public boolean isCancelled() {
46:             return true;
47:         }
48: 
49:         @Override
50:         public boolean isDone() {
51:             return true;
52:         }
53: 
54:         @Override
55:         public Void get() {
56:             return null;
57:         }
58: 
59:         @Override
60:         public Void get(long timeout, TimeUnit unit) {
61:             return null;
62:         }
63: 
64:         @Override
65:         public long getDelay(TimeUnit unit) {
66:             return 0L;
67:         }
68: 
69:         @Override
70:         public int compareTo(Delayed o) {
71:             long diff = getDelay(TimeUnit.NANOSECONDS) - o.getDelay(TimeUnit.NANOSECONDS);
72:             if (diff < 0)
73:                 return -1;
74:             else if (diff > 0)
75:                 return 1;
76:             else
77:                 return 0;
78:         }
79:     }
