81:     private static final Logger log = LoggerFactory.getLogger(KafkaScheduler.class);
82: 
83:     private final AtomicInteger schedulerThreadId = new AtomicInteger(0);
84:     private final int threads;
85:     private final boolean daemon;
86:     private final String threadNamePrefix;
87: 
88:     private volatile ScheduledThreadPoolExecutor executor;
89: 
90:     public KafkaScheduler(int threads) {
91:         this(threads, true);
92:     }
93: 
94:     public KafkaScheduler(int threads, boolean daemon) {
95:         this(threads, daemon, "kafka-scheduler-");
96:     }
97: 
98:     /*
99:      * Creates an instance of this.
100:      *
101:      * @param threads The number of threads in the thread pool
102:      * @param daemon If true the scheduler threads will be "daemon" threads and will not block jvm shutdown.
103:      * @param threadNamePrefix The name to use for scheduler threads. This prefix will have a number appended to it.
104:      */
105:     public KafkaScheduler(int threads, boolean daemon, String threadNamePrefix) {
106:         this.threads = threads;
107:         this.daemon = daemon;
108:         this.threadNamePrefix = threadNamePrefix;
109:     }
110: 
111:     @Override
112:     public void startup() {
113:         log.debug("Initializing task scheduler.");
114:         synchronized (this) {
115:             if (isStarted())
116:                 throw new IllegalStateException("This scheduler has already been started.");
117:             ScheduledThreadPoolExecutor executor = new ScheduledThreadPoolExecutor(threads);
118:             executor.setContinueExistingPeriodicTasksAfterShutdownPolicy(false);
119:             executor.setExecuteExistingDelayedTasksAfterShutdownPolicy(false);
120:             executor.setRemoveOnCancelPolicy(true);
121:             executor.setThreadFactory(runnable ->
122:                 new KafkaThread(threadNamePrefix + schedulerThreadId.getAndIncrement(), runnable, daemon));
123:             this.executor = executor;
124:         }
125:     }
126: 
127:     @Override
128:     public void shutdown() throws InterruptedException {
129:         log.debug("Shutting down task scheduler.");
130:         // We use the local variable to avoid NullPointerException if another thread shuts down scheduler at same time.
131:         ScheduledThreadPoolExecutor maybeExecutor = null;
132:         synchronized (this) {
133:             if (isStarted()) {
134:                 maybeExecutor = executor;
135:                 maybeExecutor.shutdown();
136:                 this.executor = null;
137:             }
138:         }
139:         if (maybeExecutor != null)
140:             maybeExecutor.awaitTermination(1, TimeUnit.DAYS);
141:     }
142: 
143:     @Override
144:     public ScheduledFuture<?> schedule(String name, Runnable task, long delayMs, long periodMs) {
145:         log.debug("Scheduling task {} with initial delay {} ms and period {} ms.", name, delayMs, periodMs);
146:         synchronized (this) {
147:             if (isStarted()) {
148:                 Runnable runnable = () -> {
149:                     try {
150:                         log.trace("Beginning execution of scheduled task '{}'.", name);
151:                         task.run();
152:                     } catch (Throwable t) {
153:                         log.error("Uncaught exception in scheduled task '{}'", name, t);
154:                     } finally {
155:                         log.trace("Completed execution of scheduled task '{}'.", name);
156:                     }
157:                 };
158:                 if (periodMs > 0)
159:                     return executor.scheduleAtFixedRate(runnable, delayMs, periodMs, TimeUnit.MILLISECONDS);
160:                 else
161:                     return executor.schedule(runnable, delayMs, TimeUnit.MILLISECONDS);
162:             } else {
163:                 log.info("Kafka scheduler is not running at the time task '{}' is scheduled. The task is ignored.", name);
164:                 return new NoOpScheduledFutureTask();
165:             }
166:         }
167:     }
168: 
169:     public final boolean isStarted() {
170:         return executor != null;
171:     }
172: 
173:     public void resizeThreadPool(int newSize) {
174:         synchronized (this) {
175:             if (isStarted())
176:                 executor.setCorePoolSize(newSize);
177:         }
178:     }
179: 
180:     // Visible for testing
181:     public String threadNamePrefix() {
182:         return threadNamePrefix;
183:     }
184: 
185:     // Visible for testing
186:     public boolean taskRunning(ScheduledFuture<?> task) {
187:         ScheduledThreadPoolExecutor e = executor;
188:         return e != null && e.getQueue().contains(task);
189:     }
190: 
191:     public int pendingTaskSize() {
192:         return isStarted() ? executor.getQueue().size() : 0;
193:     }
194: }
